interface UserRepository extends org.springframework.data.jpa.repository.JpaRepository<User, Long> {
    @org.springframework.data.jpa.repository.EntityGraph(attributePaths = {"orders"})
    java.util.List<User> findByStatus(String status);
}

@org.springframework.transaction.annotation.Transactional(readOnly = true)
public java.util.List<UserOrderDto> listActiveUsers() {
    java.util.List<User> users = userRepository.findByStatus("ACTIVE");
    return users.stream()
        .map(u -> new UserOrderDto(u.getId(), u.getEmail(), u.getOrders().size()))
        .toList();
}

record UserOrderDto(Long id, String email, int orderCount) {}

